if (! isset($scrollTo)) {
    $scrollTo = false;
}

$scrollIntoViewJsSnippet = ($scrollTo !== false)
    ? <<<JS
       (
           \$el.closest('{$scrollTo}') || document.querySelector('{$scrollTo}')
       ).scrollIntoView()
    JS
    : '';
